package pe.edu.utp.tmo.util; import org.apache.commons.io.FilenameUtils; import org.apache.commons.lang3.StringUtils; public final class FileNameSanitizer{private FileNameSanitizer(){} public static String safeXlsx(String n){String b=FilenameUtils.getBaseName(StringUtils.defaultIfBlank(n,"reporte_tmo")).replaceAll("[^a-zA-Z0-9._-]","_"); return (b.length()>80?b.substring(0,80):b)+".xlsx";}}